1	/**
2	 * The Instrumentarium — guild tool registry apparatus.
3	 *
4	 * Scans installed tools from kit contributions and apparatus supportKits,
5	 * resolves permission-gated tool sets on demand, and serves as the single
6	 * source of truth for "what tools exist and who can use them."
7	 *
8	 * The Instrumentarium is role-agnostic — it receives an already-resolved
9	 * permissions array from the Loom and returns the matching tool set.
10	 * Role definitions and permission grants are owned by the Loom.
11	 */
12	
13	import fs from 'node:fs';
14	import path from 'node:path';
15	
16	import type {
17	  StartupContext,
18	  LoadedPlugin,
19	  LoadedKit,
20	  LoadedApparatus,
21	  Plugin,
22	} from '@shardworks/nexus-core';
23	import {
24	  guild,
25	  isLoadedKit,
26	  isLoadedApparatus,
27	} from '@shardworks/nexus-core';
28	
29	import type { ToolDefinition, ToolCaller } from './tool.ts';
30	import { isToolDefinition } from './tool.ts';
31	import { createToolsList } from './tools/tools-list.ts';
32	import { createToolsShow } from './tools/tools-show.ts';
33	
34	// ── Public types ──────────────────────────────────────────────────────
35	
36	/** A resolved tool with provenance metadata. */
37	export interface ResolvedTool {
38	  /** The tool definition (name, description, params schema, handler). */
39	  definition: ToolDefinition;
40	  /** Plugin id of the kit or apparatus that contributed this tool. */
41	  pluginId: string;
42	}
43	
44	/** Options for resolving a permission-gated tool set. */
45	export interface ResolveOptions {
46	  /**
47	   * Permission grants in `plugin:level` format.
48	   * Supports wildcards: `plugin:*`, `*:level`, `*:*`.
49	   */
50	  permissions: string[];
51	  /**
52	   * When true, permissionless tools are excluded unless the role grants
53	   * `plugin:*` or `*:*` for the tool's plugin. When false (default),
54	   * permissionless tools are included unconditionally.
55	   */
56	  strict?: boolean;
57	  /** Filter by invocation caller. Tools with no callableBy pass all callers. */
58	  caller?: ToolCaller;
59	}
60	
61	/** The Instrumentarium's public API, exposed via `provides`. */
62	export interface InstrumentariumApi {
63	  /**
64	   * Resolve the tool set for a given set of permissions.
65	   *
66	   * Evaluates each registered tool against the permission grants:
67	   * - Tools with a `permission` field: included if any grant matches
68	   * - Permissionless tools: always included (default) or gated by `strict`
69	   * - Caller filtering applied last
70	   */
71	  resolve(options: ResolveOptions): ResolvedTool[];
72	
73	  /**
74	   * Find a single tool by name. Returns null if not installed.
75	   */
76	  find(name: string): ResolvedTool | null;
77	
78	  /**
79	   * List all installed tools, regardless of permissions.
80	   */
81	  list(): ResolvedTool[];
82	}
83	
84	// ── Permission matching ──────────────────────────────────────────────
85	
86	/** A parsed permission grant. */
87	interface ParsedGrant {
88	  plugin: string;
89	  level: string;
90	}
91	
92	/** Parse a grant string like "plugin:level" into its components. */
93	function parseGrant(grant: string): ParsedGrant | null {
94	  const colonIdx = grant.indexOf(':');
95	  if (colonIdx === -1) return null;
96	  return {
97	    plugin: grant.slice(0, colonIdx),
98	    level: grant.slice(colonIdx + 1),
99	  };
100	}
101	
102	/**
103	 * Check if a tool with the given permission level from the given plugin
104	 * is matched by any of the parsed grants.
105	 */
106	function matchesPermission(
107	  pluginId: string,
108	  permission: string,
109	  grants: ParsedGrant[],
110	): boolean {
111	  for (const grant of grants) {
112	    // Exact match: plugin:level
113	    if (grant.plugin === pluginId && grant.level === permission) return true;
114	    // Plugin wildcard: plugin:*
115	    if (grant.plugin === pluginId && grant.level === '*') return true;
116	    // Level wildcard: *:level
117	    if (grant.plugin === '*' && grant.level === permission) return true;
118	    // Superuser: *:*
119	    if (grant.plugin === '*' && grant.level === '*') return true;
120	  }
121	  return false;
122	}
123	
124	/**
125	 * Check if a permissionless tool from the given plugin should be included
126	 * in strict mode. Only `plugin:*` or `*:*` opts in permissionless tools.
127	 */
128	function strictAllowsPermissionless(
129	  pluginId: string,
130	  grants: ParsedGrant[],
131	): boolean {
132	  for (const grant of grants) {
133	    if (grant.plugin === pluginId && grant.level === '*') return true;
134	    if (grant.plugin === '*' && grant.level === '*') return true;
135	  }
136	  return false;
137	}
138	
139	// ── Implementation ────────────────────────────────────────────────────
140	
141	/**
142	 * The tool registry — accumulates tools from plugin contributions
143	 * and resolves permission-gated tool sets.
144	 */
145	class ToolRegistry {
146	  /** Map from tool name → ResolvedTool. Last-write-wins for duplicates. */
147	  private readonly tools = new Map<string, ResolvedTool>();
148	  /** Guild root path — set at startup, used for instructionsFile resolution. */
149	  private guildHome = '';
150	
151	  /** Set the guild root path for instructionsFile resolution. */
152	  setHome(home: string): void {
153	    this.guildHome = home;
154	  }
155	
156	  /** Register all tools from a loaded plugin. */
157	  register(plugin: LoadedPlugin): void {
158	    const pluginId = plugin.id;
159	    const packageName = plugin.packageName;
160	
161	    if (isLoadedKit(plugin)) {
162	      this.registerToolsFromKit(pluginId, packageName, plugin.kit);
163	    } else if (isLoadedApparatus(plugin)) {
164	      if (plugin.apparatus.supportKit) {
165	        this.registerToolsFromKit(pluginId, packageName, plugin.apparatus.supportKit);
166	      }
167	    }
168	  }
169	
170	  /** Extract and register tools from a kit (or supportKit) contribution. */
171	  private registerToolsFromKit(
172	    pluginId: string,
173	    packageName: string,
174	    kit: Record<string, unknown>,
175	  ): void {
176	    const rawTools = kit.tools;
177	    if (!Array.isArray(rawTools)) return;
178	
179	    for (const t of rawTools) {
180	      if (isToolDefinition(t)) {
181	        const definition = this.preloadInstructions(t, packageName);
182	        this.tools.set(definition.name, { definition, pluginId });
183	      }
184	    }
185	  }
186	
187	  /**
188	   * Pre-load instructionsFile into instructions text.
189	   *
190	   * If the tool has an `instructionsFile`, resolve it relative to the
191	   * package root in node_modules, read the file, and return a copy with
192	   * `instructions` set to the file content and `instructionsFile` cleared.
193	   *
194	   * Tools with inline `instructions` or neither field are returned as-is.
195	   */
196	  private preloadInstructions(
197	    tool: ToolDefinition,
198	    packageName: string,
199	  ): ToolDefinition {
200	    if (!tool.instructionsFile) return tool;
201	
202	    const packageDir = path.join(this.guildHome, 'node_modules', packageName);
203	    const filePath = path.join(packageDir, tool.instructionsFile);
204	
205	    try {
206	      const content = fs.readFileSync(filePath, 'utf-8');
207	      // Return a mutated copy — instructionsFile consumed, instructions set
208	      const { instructionsFile: _, ...rest } = tool;
209	      return { ...rest, instructions: content } as ToolDefinition;
210	    } catch {
211	      console.warn(
212	        `[instrumentarium] Could not read instructions file for tool "${tool.name}": ${filePath}`,
213	      );
214	      // Return tool without instructions — don't block registration
215	      const { instructionsFile: _, ...rest } = tool;
216	      return rest as ToolDefinition;
217	    }
218	  }
219	
220	  /** Register a single tool definition directly (for self-contributed tools). */
221	  registerTool(definition: ToolDefinition, pluginId: string): void {
222	    this.tools.set(definition.name, { definition, pluginId });
223	  }
224	
225	  /** Find a tool by name. */
226	  find(name: string): ResolvedTool | null {
227	    return this.tools.get(name) ?? null;
228	  }
229	
230	  /** List all installed tools. */
231	  list(): ResolvedTool[] {
232	    return [...this.tools.values()];
233	  }
234	
235	  /**
236	   * Resolve a permission-gated tool set.
237	   *
238	   * 1. Parse each grant into (plugin, level) pairs
239	   * 2. For each registered tool:
240	   *    a. If tool has no permission:
241	   *       - If NOT strict → include
242	   *       - If strict → include only if grants contain <tool's plugin>:* or *:*
243	   *    b. If tool has a permission:
244	   *       - Match against grants: exact, plugin wildcard, level wildcard, or superuser
245	   *       - Include if any grant matches
246	   * 3. Filter by caller (callableBy)
247	   */
248	  resolve(options: ResolveOptions): ResolvedTool[] {
249	    const grants = options.permissions
250	      .map(parseGrant)
251	      .filter((g): g is ParsedGrant => g !== null);
252	    const strict = options.strict ?? false;
253	
254	    const result: ResolvedTool[] = [];
255	
256	    for (const resolved of this.tools.values()) {
257	      const { definition, pluginId } = resolved;
258	      const permission = definition.permission;
259	
260	      // Permission check
261	      if (permission === undefined) {
262	        // Permissionless tool
263	        if (strict && !strictAllowsPermissionless(pluginId, grants)) {
264	          continue;
265	        }
266	        // In default mode, permissionless tools are always included
267	      } else {
268	        // Tool has a permission — must match against grants
269	        if (!matchesPermission(pluginId, permission, grants)) {
270	          continue;
271	        }
272	      }
273	
274	      // Caller filter
275	      if (
276	        options.caller &&
277	        definition.callableBy &&
278	        !definition.callableBy.includes(options.caller)
279	      ) {
280	        continue;
281	      }
282	
283	      result.push(resolved);
284	    }
285	
286	    return result;
287	  }
288	}
289	
290	// ── Apparatus factory ─────────────────────────────────────────────────
291	
292	/**
293	 * Create the Instrumentarium apparatus plugin.
294	 *
295	 * Returns a Plugin with:
296	 * - `consumes: ['tools']` — scans kit/supportKit contributions
297	 * - `provides: InstrumentariumApi` — the tool registry API
298	 */
299	export function createInstrumentarium(): Plugin {
300	  const registry = new ToolRegistry();
301	
302	  const api: InstrumentariumApi = {
303	    resolve(options: ResolveOptions): ResolvedTool[] {
304	      return registry.resolve(options);
305	    },
306	
307	    find(name: string): ResolvedTool | null {
308	      return registry.find(name);
309	    },
310	
311	    list(): ResolvedTool[] {
312	      return registry.list();
313	    },
314	  };
315	
316	  // Introspection tools use a lazy getter so they can query the registry
317	  // after all plugins have registered their tools at startup.
318	  const getApi = () => api;
319	  const toolsList = createToolsList(getApi);
320	  const toolsShow = createToolsShow(getApi);
321	
322	  return {
323	    apparatus: {
324	      requires: [],
325	      consumes: ['tools'],
326	      provides: api,
327	
328	      supportKit: {
329	        tools: [toolsList, toolsShow],
330	      },
331	
332	      start(ctx: StartupContext): void {
333	        const g = guild();
334	        registry.setHome(g.home);
335	
336	        // Register our own supportKit tools (tools-list, tools-show).
337	        // These live on this apparatus and aren't discovered through the
338	        // normal kit scanning path.
339	        for (const t of [toolsList, toolsShow] as ToolDefinition[]) {
340	          registry.registerTool(t, 'tools');
341	        }
342	
343	        // Scan all already-loaded kits. These fired plugin:initialized before
344	        // any apparatus started, so we can't catch them via events.
345	        for (const kit of g.kits()) {
346	          registry.register(kit);
347	        }
348	
349	        // Subscribe to plugin:initialized for apparatus supportKits that
350	        // fire after us in the startup sequence.
351	        ctx.on('plugin:initialized', (plugin: unknown) => {
352	          const loaded = plugin as LoadedPlugin;
353	          // Skip kits — we already scanned them above.
354	          if (isLoadedApparatus(loaded)) {
355	            registry.register(loaded);
356	          }
357	        });
358	      },
359	    },
360	  };
361	}
