1	/**
2	 * Arbor — the guild runtime.
3	 *
4	 * `createGuild()` is the single entry point. It reads guild.json, loads all
5	 * declared plugins, validates dependencies, starts apparatus in order, wires
6	 * the guild() singleton, and returns the Guild object.
7	 *
8	 * The full plugin lifecycle:
9	 *   1. Load    — imports all declared plugin packages, discriminates kit vs apparatus
10	 *   2. Validate — checks `requires` declarations, detects circular dependencies
11	 *   3. Start   — calls start(ctx) on each apparatus in dependency-resolved order
12	 *   4. Events  — fires `plugin:initialized` after each plugin loads
13	 *   5. Warn    — advisory warnings for mismatched kit contributions / recommends
14	 *
15	 * Pure logic (validation, ordering, events) lives in guild-lifecycle.ts.
16	 * This file handles I/O and orchestration.
17	 */
18	
19	import {
20	  readGuildConfig,
21	  writeGuildConfig,
22	  findGuildRoot,
23	  isKit,
24	  isApparatus,
25	  setGuild,
26	  resolveGuildPackageEntry,
27	  resolvePackageNameForPluginId,
28	  readGuildPackageJson,
29	} from '@shardworks/nexus-core';
30	import type {
31	  Guild,
32	  LoadedKit,
33	  LoadedApparatus,
34	  FailedPlugin,
35	} from '@shardworks/nexus-core';
36	
37	import {
38	  validateRequires,
39	  filterFailedPlugins,
40	  topoSort,
41	  collectStartupWarnings,
42	  buildStartupContext,
43	  fireEvent,
44	} from './guild-lifecycle.ts';
45	import type { EventHandlerMap } from './guild-lifecycle.ts';
46	
47	// ── Public API ────────────────────────────────────────────────────────
48	
49	/**
50	 * Create and start a guild.
51	 *
52	 * Reads guild.json, loads all declared plugins, validates dependencies,
53	 * starts apparatus in dependency order, and returns the Guild object.
54	 * Also sets the guild() singleton so apparatus code can access it.
55	 *
56	 * @param root - Absolute path to the guild root. Defaults to auto-detection
57	 *               by walking up from cwd until guild.json is found.
58	 * @returns The initialized Guild — the same object guild() returns.
59	 */
60	export async function createGuild(root?: string): Promise<Guild> {
61	  const guildRoot = root ?? findGuildRoot();
62	  const config = readGuildConfig(guildRoot);
63	
64	  const kits:        LoadedKit[]        = [];
65	  const apparatuses: LoadedApparatus[]  = [];
66	  const eventHandlers: EventHandlerMap = new Map();
67	
68	  // ── Load phase ─────────────────────────────────────────────────────
