531	// ── Tool execution ─────────────────────────────────────────────────
532	
533	/**
534	 * Execute a single tool call and return the result string.
535	 *
536	 * Catches all errors and returns them as error strings rather than
537	 * propagating — the model receives the error and may retry or recover.
538	 */
539	async function executeToolCall(
540	  toolCall: ToolCall,
541	  toolMap: Map<string, ResolvedTool>,
542	): Promise<string> {
543	  const tool = toolMap.get(toolCall.function.name);
544	  if (!tool) {
545	    return `Error: Unknown tool: ${toolCall.function.name}`;
546	  }
547	
548	  try {
549	    const args = JSON.parse(toolCall.function.arguments) as unknown;
550	    const parsed = tool.definition.params.parse(args);
551	    const rawResult = await tool.definition.handler(parsed);
552	    if (typeof rawResult === 'string') return rawResult;
553	    return JSON.stringify(rawResult, null, 2);
554	  } catch (err) {
555	    const message = err instanceof Error ? err.message : String(err);
556	    return `Error: ${message}`;
557	  }
558	}
