564	 *
565	 * The apparatus reads CopilotConfig from guild config at start() time
566	 * and provides an AnimatorSessionProvider backed by the GitHub Models API.
567	 */
568	export function createCopilotProvider(): Plugin {
569	  let config: CopilotConfig = {};
570	
