594	      }
595	      if (sessionConfig.initialPrompt) {
596	        const userMsg: ChatMessage = { role: 'user', content: sessionConfig.initialPrompt };
597	        messages.push(userMsg);
598	        acc.transcript.push(userMsg as TranscriptEntry);
599	      }
600	
601	      // Convert tools
602	      const tools = sessionConfig.tools ?? [];
603	      const apiTools = convertTools(tools);
604	      const toolMap = new Map<string, ResolvedTool>(
605	        tools.map((rt) => [rt.definition.name, rt]),
606	      );
607	
608	      if (sessionConfig.streaming) {
609	        // ── Streaming mode ────────────────────────────────────────────
610	        // Use a push queue + resolve callback to bridge the async generator
611	        // into a pull-based async iterable.
612	
613	        const chunkQueue: SessionChunk[] = [];
614	        let chunkResolve: (() => void) | null = null;
615	        let done = false;
616	        let streamError: Error | null = null;
617	
618	        const result: Promise<SessionProviderResult> = (async () => {
619	          // Validate token
620	          const token = process.env[tokenEnvVar];
621	          if (!token) {
622	            throw new Error(
623	              `Copilot session provider requires a GitHub token. ` +
624	              `Set the ${tokenEnvVar} environment variable.`,
625	            );
626	          }
627	
628	          try {
629	            const gen = runAgenticLoopStreaming(
630	              apiEndpoint, token, sessionConfig.model, messages, apiTools, toolMap, maxRounds, acc,
631	            );
632	
633	            for await (const chunk of gen) {
634	              chunkQueue.push(chunk);
635	              // eslint-disable-next-line @typescript-eslint/no-unnecessary-type-assertion
636	              const notify = chunkResolve as (() => void) | null;
637	              chunkResolve = null;
638	              notify?.();
639	            }
